mapper.select:
SELECT t.fentryid, t.fbillno, t.fbcykc, bd.name AS f_sfxp, t.f_jqhx, bm.number AS fplanmaterialid, t.fplanmaterialname,
bdy.name AS fplanunitid, t.fqty, t.fmaterialpriceunitqty, t.fmaterialpriceunitid, t.fprice, t.ftaxprice, t.fentrytaxrate, t.fentrytaxamount, t.fallamount, t.fbasecanoutqty, t.fdeliqty, t.fstockbasecanoutqty, t.f_ora_text1, t.f_ora_date3, t.f_fzr, t.f_ora_text, t.f_ora_date1, t.f_ora_date2, t.fpurjoinqty, t.f_ora_base1, t.f_ycjjfa, t.f_ora_decimal, t.f_ora_date4, t.f_ora_decimal1, t.f_ora_integer2, t.f_ora_date5, t.f_ora_integer3, t.f_bzjdtwo, sp.number AS f_ora_base, t.f_ora_integer, t.f_ora_date, t.f_mz, t.f_jz, t.f_mzz, t.f_zxs, t.f_xs, t.f_gdtp1, t.f_gdtp2, t.f_xdgjjdtwo, t.f_bzfs, t.f_tsyq, t.f_ljrksl, t.fysbz, t.f_bgrq, t.f_ctt, t.f_cptp, t.f_gcbz, t.fhhwrk, t.f_kpdj, t.f_bzxdzt, t.f_gxzt, t.f_cht, t.f_jgt, t.f_smsfj, t.f_bchqzt, t.f_tsl, t.f_bgywpm, t.f_bgdw, t.f_ygcb, t.f_hsbm, t.f_sbys, t.f_bcfynew, t.f_glbcfynew, t.fbzcc, t.fbzgctg, t.frkshrq, t.fbjr, t.ftpr, t.f_cty_baseproperty4, t.fkhywms, t.f_cty_baseproperty6, t.f_ygcbdj, t.f_ygcbdj1, t.f_ygcb1, t.f_peuu_attachment_83g, t.fcgddshrq, t.fyjsj, t.fslshrq, t.f_xlcp, bly.name AS f_cplb, t.f_ckrq, t.f_cty_baseproperty8 FROM t_sale_order_entry t LEFT JOIN bymaterial_dictionary bd ON bd.kingdee = t.f_sfxp AND bd.category = 'Order_product_category' LEFT JOIN bymaterial_dictionary bdy ON bdy.kingdee = t.fplanunitid AND bdy.category = 'unit' LEFT JOIN bymaterial_dictionary bly ON bly.kingdee = t.f_cplb AND bly.category = 'product_category' LEFT JOIN by_material bm ON bm.k3_id = t.fplanmaterialid LEFT JOIN supplier sp ON sp.supplierid = t.f_ora_base
WHERE fbillno = #{fbillNo}

mapper.delete:
DELETE FROM t_sale_order_entry
WHERE fbillno IN

    #{fbillno}
